import { useState } from "react";
import axios from "axios";
import { generateKeyPair } from "../utils/crypto";

export default function SignupPage({ setUser, setPage }) {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [phone, setPhone] = useState("");

  const signup = async () => {
    try {
      // Create user in backend
      const res = await axios.post("http://localhost:5001/user/register", {
        name, email, password, phone
      });

      if (res.data.success) {
        // Generate keypair on client
        const { publicKey, privateKey } = await generateKeyPair();

        // Save public key in backend
        await axios.post("http://localhost:5001/user/saveKey", {
          phone,
          publicKey
        });

        // Store private key locally (never send to server)
        localStorage.setItem("privateKey", privateKey);

        // Attach keys to user object
        const userObj = { ...res.data.user, publicKey, privateKey };
        setUser(userObj);
        setPage("chat");
      }
    } catch (err) {
      alert("Signup failed");
    }
  };

  return (
    <div style={{ padding: 50 }}>
      <h2>Signup</h2>
      <input placeholder="Name" onChange={e => setName(e.target.value)} /><br />
      <input placeholder="Email" onChange={e => setEmail(e.target.value)} /><br />
      <input placeholder="Password" type="password" onChange={e => setPassword(e.target.value)} /><br />
      <input placeholder="Phone" onChange={e => setPhone(e.target.value)} /><br />
      <button onClick={signup}>Signup</button>
    </div>
  );
}
